// Script: generar_103_respiracion_tracker.js
// Que hace: agrega el Tracker de Frecuencia Respiratoria en Prevencion
// dentro de la seccion Peso (como una subseccion debajo del grafico
// de peso). Solo aparece para perros.
//
// IMPORTANTE: primero correr el SQL en Supabase:
// 13_frecuencia_respiratoria.sql
//
// Incluye:
//   - Instrucciones desplegables sobre como medir correctamente
//   - Input del valor en rpm con feedback inmediato del semaforo
//   - Grafico de barras con zonas coloreadas (normal/atencion/urgente)
//   - Historial de mediciones con color segun estado
//
// Valores de referencia (Dr. hermano cardiologo veterinario):
//   🟢 Normal:   15-30 rpm
//   🟡 Atencion: 30-40 rpm
//   🔴 Urgente:  +40 rpm
//
//   1) components/RespiracionTracker.tsx (ARCHIVO NUEVO)
//   2) app/prevencion/page.tsx (agrega el componente en seccion Peso)

const fs = require('fs'); const path = require('path');
function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64,'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir,{recursive:true});
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}
escribir('components/RespiracionTracker.tsx', "");
escribir('app/prevencion/page.tsx', "");
